import requests
import json
import sys
from requests.auth import HTTPBasicAuth
from typing import List, Dict, Any
import os

class RabbitMQConfigurator:
    def __init__(self, host: str, port: int = 15672, username: str = None, password: str = None):
        self.host = host
        self.port = port
        self.base_url = f"http://{host}:{port}/api"
        self.auth = HTTPBasicAuth(username or os.getenv('RABBITMQ_DEFAULT_USER', 'guest'), 
                                password or os.getenv('RABBITMQ_DEFAULT_PASS', 'guest'))
        
    def _make_request(self, method: str, endpoint: str, data: Dict = None) -> requests.Response:
        url = f"{self.base_url}{endpoint}"
        headers = {'Content-Type': 'application/json'}
        
        if method.upper() == 'GET':
            response = requests.get(url, auth=self.auth, headers=headers)
        elif method.upper() == 'POST':
            response = requests.post(url, auth=self.auth, headers=headers, data=json.dumps(data))
        elif method.upper() == 'PUT':
            response = requests.put(url, auth=self.auth, headers=headers, data=json.dumps(data))
        elif method.upper() == 'DELETE':
            response = requests.delete(url, auth=self.auth, headers=headers)
            
        response.raise_for_status()
        return response
    
    def create_vhost(self, vhost_name: str) -> bool:
        try:
            self._make_request('PUT', f'/vhosts/{vhost_name}')
            return True
        except requests.exceptions.HTTPError as e:
            if e.response.status_code == 409:
                print(f"Vhost {vhost_name} already exists")
                return True
            raise e
    
    def delete_vhost(self, vhost_name: str) -> bool:
        try:
            self._make_request('DELETE', f'/vhosts/{vhost_name}')
            return True
        except requests.exceptions.HTTPError as e:
            if e.response.status_code == 404:
                print(f"Vhost {vhost_name} does not exist")
                return True
            raise e
    
    def create_user(self, username: str, password: str, tags: List[str] = None) -> bool:
        try:
            user_data = {
                "password": password,
                "tags": tags or ""
            }
            self._make_request('PUT', f'/users/{username}', data=user_data)
            return True
        except requests.exceptions.HTTPError as e:
            if e.response.status_code == 409:
                print(f"User {username} already exists")
                return True
            raise e
    
    def delete_user(self, username: str) -> bool:
        try:
            self._make_request('DELETE', f'/users/{username}')
            return True
        except requests.exceptions.HTTPError as e:
            if e.response.status_code == 404:
                print(f"User {username} does not exist")
                return True
            raise e
    
    def set_permissions(self, username: str, vhost_name: str, configure: str, write: str, read: str) -> bool:
        try:
            permissions_data = {
                "configure": configure,
                "write": write,
                "read": read
            }
            self._make_request('PUT', f'/permissions/{vhost_name}/{username}', data=permissions_data)
            return True
        except requests.exceptions.HTTPError as e:
            raise e
    
    def get_vhosts(self) -> List[Dict[str, Any]]:
        response = self._make_request('GET', '/vhosts')
        return response.json()
    
    def get_users(self) -> List[Dict[str, Any]]:
        response = self._make_request('GET', '/users')
        return response.json()
    
    def validate_vhost_name(self, vhost_name: str) -> bool:
        if not vhost_name or not isinstance(vhost_name, str):
            return False
        if vhost_name.startswith('/') or vhost_name.endswith('/'):
            return False
        if '..' in vhost_name:
            return False
        if len(vhost_name) > 128:
            return False
        return True
    
    def validate_username(self, username: str) -> bool:
        if not username or not isinstance(username, str):
            return False
        if len(username) > 128:
            return False
        if username.startswith('/') or username.endswith('/'):
            return False
        return True

def main():
    # Configuration
    RABBITMQ_HOST = os.getenv('RABBITMQ_HOST', 'localhost')
    RABBITMQ_USER = os.getenv('RABBITMQ_USER', 'guest')
    RABBITMQ_PASS = os.getenv('RABBITMQ_PASS', 'guest')
    
    configurator = RabbitMQConfigurator(RABBITMQ_HOST, username=RABBITMQ_USER, password=RABBITMQ_PASS)
    
    # Example tenant configuration
    tenants = [
        {
            "name": "tenant1",
            "users": [
                {
                    "username": "tenant1_user",
                    "password": os.getenv('TENANT1_USER_PASS', 'secure_password_1'),
                    "permissions": {
                        "configure": ".*",
                        "write": ".*",
                        "read": ".*"
                    }
                }
            ]
        },
        {
            "name": "tenant2",
            "users": [
                {
                    "username": "tenant2_user",
                    "password": os.getenv('TENANT2_USER_PASS', 'secure_password_2'),
                    "permissions": {
                        "configure": ".*",
                        "write": ".*",
                        "read": ".*"
                    }
                }
            ]
        }
    ]
    
    for tenant in tenants:
        vhost_name = tenant["name"]
        
        # Validate vhost name
        if not configurator.validate_vhost_name(vhost_name):
            print(f"Invalid vhost name: {vhost_name}")
            continue
            
        # Create vhost
        if configurator.create_vhost(vhost_name):
            print(f"Created vhost: {vhost_name}")
        
        # Create users for tenant
        for user_config in tenant["users"]:
            username = user_config["username"]
            
            # Validate username
            if not configurator.validate_username(username):
                print(f"Invalid username: {username}")
                continue
                
            # Create user
            if configurator.create_user(username, user_config["password"]):
                print(f"Created user: {username}")
                
            # Set permissions for user on vhost
            permissions = user_config["permissions"]
            if configurator.set_permissions(username, vhost_name, 
                                          permissions["configure"], 
                                          permissions["write"], 
                                          permissions["read"]):
                print(f"Set permissions for user {username} on vhost {vhost_name}")

if __name__ == "__main__":
    main()